import{_ as t,o as e,c as o,ag as l}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"MCP 설치 실습","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/3-바이브코딩기초/3-4-mcp설치실습.md","filePath":"학습자료/3-바이브코딩기초/3-4-mcp설치실습.md"}'),s={name:"학습자료/3-바이브코딩기초/3-4-mcp설치실습.md"};function i(n,a,d,p,r,c){return e(),o("div",null,[...a[0]||(a[0]=[l(`<h1 id="mcp-설치-실습" tabindex="-1">MCP 설치 실습 <a class="header-anchor" href="#mcp-설치-실습" aria-label="Permalink to &quot;MCP 설치 실습&quot;">​</a></h1><p>MCP가 뭔지는 알겠는데, 실제로 어떻게 설치하나요? 직접 해봅시다.</p><p>오늘은 3가지 MCP를 설치합니다. 쉬운 것부터 차근차근 갑니다.</p><hr><h2 id="part-a-context7-mcp-확인" tabindex="-1">Part A: Context7 MCP 확인 <a class="header-anchor" href="#part-a-context7-mcp-확인" aria-label="Permalink to &quot;Part A: Context7 MCP 확인&quot;">​</a></h2><blockquote><p>가장 간단한 MCP입니다. 이미 사전준비에서 설치되어 있을 수 있어요.</p></blockquote><h3 id="context7이-뭔가요" tabindex="-1">Context7이 뭔가요? <a class="header-anchor" href="#context7이-뭔가요" aria-label="Permalink to &quot;Context7이 뭔가요?&quot;">​</a></h3><p>프로그래밍 라이브러리의 <strong>최신 공식 문서</strong>를 AI가 직접 조회할 수 있게 해주는 MCP입니다. 비개발자에게는 &quot;AI가 최신 정보를 직접 찾아볼 수 있게 해주는 연결&quot;이라고 이해하면 됩니다.</p><h3 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h3><p>Claude Code에게 물어보세요:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>현재 연결된 MCP 서버 목록을 보여줘</span></span></code></pre></div><p><code>context7</code> 이 목록에 있으면 이미 설치된 겁니다!</p><h3 id="없다면-설치하기" tabindex="-1">없다면 설치하기 <a class="header-anchor" href="#없다면-설치하기" aria-label="Permalink to &quot;없다면 설치하기&quot;">​</a></h3><p>Claude Code에게:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Context7 MCP 서버를 설치해줘</span></span></code></pre></div><h3 id="테스트" tabindex="-1">테스트 <a class="header-anchor" href="#테스트" aria-label="Permalink to &quot;테스트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Context7을 사용해서 VitePress의 최신 설정 방법을 알려줘</span></span></code></pre></div><p>AI가 최신 문서를 기반으로 답변하면 성공!</p><div class="tip custom-block"><p class="custom-block-title">Part A 체크리스트</p><ul><li>[ ] Context7 MCP가 연결되어 있는지 확인했다</li><li>[ ] 없으면 설치했다</li><li>[ ] 테스트 질문에 최신 문서 기반 답변을 받았다</li></ul></div><hr><h2 id="part-b-chrome-devtools-mcp-설치" tabindex="-1">Part B: Chrome DevTools MCP 설치 <a class="header-anchor" href="#part-b-chrome-devtools-mcp-설치" aria-label="Permalink to &quot;Part B: Chrome DevTools MCP 설치&quot;">​</a></h2><blockquote><p>AI가 웹 브라우저를 직접 제어하고 스크린샷을 찍을 수 있게 해주는 MCP입니다.</p></blockquote><h3 id="왜-필요한가요" tabindex="-1">왜 필요한가요? <a class="header-anchor" href="#왜-필요한가요" aria-label="Permalink to &quot;왜 필요한가요?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>MCP 없을 때</th><th>MCP 있을 때</th></tr></thead><tbody><tr><td>&quot;이 웹페이지 캡처해서 보내줘&quot; → 직접 캡처해야 함</td><td>&quot;이 페이지 스크린샷 찍어줘&quot; → AI가 직접 캡처</td></tr><tr><td>&quot;이 버튼 눌러봐&quot; → 직접 클릭해야 함</td><td>&quot;로그인 버튼 클릭해줘&quot; → AI가 직접 조작</td></tr></tbody></table><h3 id="설치하기" tabindex="-1">설치하기 <a class="header-anchor" href="#설치하기" aria-label="Permalink to &quot;설치하기&quot;">​</a></h3><p>Claude Code에게 자연어로 요청하세요:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chrome DevTools MCP 서버를 설치해줘</span></span></code></pre></div><p>Claude Code가 알아서:</p><ol><li>필요한 패키지를 설치하고</li><li>설정 파일(<code>.mcp.json</code>)에 등록하고</li><li>연결 확인까지 해줍니다</li></ol><h3 id="테스트-스크린샷-찍기" tabindex="-1">테스트: 스크린샷 찍기 <a class="header-anchor" href="#테스트-스크린샷-찍기" aria-label="Permalink to &quot;테스트: 스크린샷 찍기&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://claude.ai 페이지를 열고 스크린샷을 찍어줘</span></span></code></pre></div><p>스크린샷 이미지가 생성되면 성공!</p><details class="details custom-block"><summary>잘 안 되면?</summary><table tabindex="0"><thead><tr><th>문제</th><th>해결</th></tr></thead><tbody><tr><td>&quot;Chrome을 찾을 수 없습니다&quot;</td><td>Chrome 브라우저가 설치되어 있는지 확인</td></tr><tr><td>&quot;연결할 수 없습니다&quot;</td><td>Chrome을 완전히 종료한 후 다시 시도</td></tr><tr><td>설정 오류</td><td>Claude Code에게 &quot;MCP 설정 파일 확인해줘&quot;라고 요청</td></tr></tbody></table></details><div class="tip custom-block"><p class="custom-block-title">Part B 체크리스트</p><ul><li>[ ] Chrome DevTools MCP를 설치했다</li><li>[ ] 스크린샷 테스트가 성공했다</li></ul></div><hr><h2 id="part-c-google-calendar-mcp-설치" tabindex="-1">Part C: Google Calendar MCP 설치 <a class="header-anchor" href="#part-c-google-calendar-mcp-설치" aria-label="Permalink to &quot;Part C: Google Calendar MCP 설치&quot;">​</a></h2><blockquote><p>AI가 내 Google 캘린더를 직접 읽고, 일정을 추가할 수 있게 해주는 MCP입니다. 이건 조금 더 복잡하지만, 설치 후 효과가 가장 큽니다!</p></blockquote><h3 id="왜-필요한가요-1" tabindex="-1">왜 필요한가요? <a class="header-anchor" href="#왜-필요한가요-1" aria-label="Permalink to &quot;왜 필요한가요?&quot;">​</a></h3><p>설치 후에는 이런 대화가 가능해집니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>👤 &quot;내일 일정 알려줘&quot;</span></span>
<span class="line"><span>🤖 &quot;내일 오전 10시 팀 미팅, 오후 2시 고객 미팅이 있습니다.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>👤 &quot;금요일 오후 3시에 주간회의 잡아줘&quot;</span></span>
<span class="line"><span>🤖 &quot;금요일 15:00에 &#39;주간회의&#39; 일정을 추가했습니다.&quot;</span></span></code></pre></div><h3 id="oauth-설정이-필요합니다" tabindex="-1">OAuth 설정이 필요합니다 <a class="header-anchor" href="#oauth-설정이-필요합니다" aria-label="Permalink to &quot;OAuth 설정이 필요합니다&quot;">​</a></h3><p>Google Calendar은 개인 정보이기 때문에 <strong>인증(OAuth)</strong> 과정이 필요합니다. 복잡해 보이지만 한 번만 하면 됩니다.</p><h3 id="step-1-google-cloud-console-설정" tabindex="-1">Step 1: Google Cloud Console 설정 <a class="header-anchor" href="#step-1-google-cloud-console-설정" aria-label="Permalink to &quot;Step 1: Google Cloud Console 설정&quot;">​</a></h3><p>Claude Code에게:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Google Calendar MCP를 설치하고 싶어.</span></span>
<span class="line"><span>OAuth 설정부터 안내해줘.</span></span></code></pre></div><p>Claude Code가 단계별로 안내해줍니다:</p><ol><li><strong>Google Cloud Console</strong> 접속 (<a href="https://console.cloud.google.com" target="_blank" rel="noreferrer">console.cloud.google.com</a>)</li><li>새 프로젝트 생성</li><li>Google Calendar API 활성화</li><li>OAuth 동의 화면 설정</li><li>OAuth 클라이언트 ID 생성 → JSON 파일 다운로드</li></ol><div class="warning custom-block"><p class="custom-block-title">이 과정이 가장 어렵습니다</p><p>Google Cloud Console이 처음이면 낯설 수 있어요. <strong>Claude Code에게 하나씩 물어보면서</strong> 진행하세요. 막히면 손 들어주세요!</p></div><h3 id="step-2-mcp-설정" tabindex="-1">Step 2: MCP 설정 <a class="header-anchor" href="#step-2-mcp-설정" aria-label="Permalink to &quot;Step 2: MCP 설정&quot;">​</a></h3><p>JSON 키 파일을 다운받았다면, Claude Code에게:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>이 OAuth JSON 파일로 Google Calendar MCP를 설정해줘.</span></span>
<span class="line"><span>파일 위치: ~/Downloads/client_secret_xxxx.json</span></span></code></pre></div><h3 id="step-3-인증-완료" tabindex="-1">Step 3: 인증 완료 <a class="header-anchor" href="#step-3-인증-완료" aria-label="Permalink to &quot;Step 3: 인증 완료&quot;">​</a></h3><p>브라우저가 열리면서 Google 로그인 화면이 나옵니다.</p><ol><li>Google 계정 선택</li><li><strong>허용</strong> 클릭</li><li>터미널/VS Code로 돌아오기</li></ol><h3 id="테스트-일정-조회" tabindex="-1">테스트: 일정 조회 <a class="header-anchor" href="#테스트-일정-조회" aria-label="Permalink to &quot;테스트: 일정 조회&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>오늘 일정을 알려줘</span></span></code></pre></div><p>내 Google Calendar의 일정이 나오면 성공!</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>내일 오후 2시에 &quot;Claude Code 복습&quot; 일정을 추가해줘</span></span></code></pre></div><p>캘린더에 일정이 추가되면 완벽합니다!</p><details class="details custom-block"><summary>잘 안 되면?</summary><table tabindex="0"><thead><tr><th>문제</th><th>해결</th></tr></thead><tbody><tr><td>&quot;API가 활성화되지 않았습니다&quot;</td><td>Google Cloud Console에서 Calendar API 활성화 확인</td></tr><tr><td>&quot;인증 실패&quot;</td><td>OAuth JSON 파일 경로가 맞는지 확인</td></tr><tr><td>&quot;권한이 없습니다&quot;</td><td>OAuth 동의 화면에서 calendar 범위(scope) 추가</td></tr><tr><td>브라우저가 안 열림</td><td>수동으로 터미널에 출력된 URL 복사해서 브라우저에 붙여넣기</td></tr></tbody></table></details><div class="tip custom-block"><p class="custom-block-title">Part C 체크리스트</p><ul><li>[ ] Google Cloud Console에서 프로젝트를 만들었다</li><li>[ ] Calendar API를 활성화했다</li><li>[ ] OAuth 클라이언트 ID를 만들고 JSON 파일을 받았다</li><li>[ ] MCP 설정을 완료했다</li><li>[ ] &quot;오늘 일정 알려줘&quot;에 실제 일정이 나온다</li><li>[ ] 새 일정을 추가할 수 있다</li></ul></div><hr><h2 id="전체-완료-체크리스트" tabindex="-1">전체 완료 체크리스트 <a class="header-anchor" href="#전체-완료-체크리스트" aria-label="Permalink to &quot;전체 완료 체크리스트&quot;">​</a></h2><ul><li>[ ] <strong>Context7</strong>: AI가 최신 문서를 조회할 수 있다</li><li>[ ] <strong>Chrome DevTools</strong>: AI가 웹페이지 스크린샷을 찍을 수 있다</li><li>[ ] <strong>Google Calendar</strong>: AI가 내 일정을 읽고 추가할 수 있다</li></ul><div class="tip custom-block"><p class="custom-block-title">축하합니다!</p><p>3개의 MCP를 설치했다면, 여러분의 AI는 이제:</p><ul><li>최신 정보를 직접 찾아보고</li><li>웹 브라우저를 직접 조작하고</li><li>캘린더를 직접 관리하는</li></ul><p><strong>진짜 비서</strong>가 된 겁니다!</p></div><hr><h2 id="mcp-설정-파일-위치" tabindex="-1">MCP 설정 파일 위치 <a class="header-anchor" href="#mcp-설정-파일-위치" aria-label="Permalink to &quot;MCP 설정 파일 위치&quot;">​</a></h2><p>설치한 MCP 설정은 이 파일에 저장됩니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/.mcp.json</span></span></code></pre></div><p>나중에 MCP를 추가하거나 수정하고 싶으면 이 파일을 확인하세요. Claude Code에게 &quot;MCP 설정 보여줘&quot;라고 하면 쉽게 볼 수 있습니다.</p><hr><p><strong><a href="/학습자료/4-워크샵실습/4-1-나만의스킬설계">나만의 스킬 설계 →</a></strong></p>`,72)])])}const b=t(s,[["render",i]]);export{u as __pageData,b as default};
